/**
 * Bing 每日一图 API - Cloudflare Workers 边缘函数
 * 
 * 功能：获取 Bing 搜索引擎每日更新的背景图片
 * 遵循：Cloudflare Workers 最佳实践和开发标准
 * 
 * 主要特性：
 * - 完整的 CORS 支持（预检请求处理）
 * - 请求超时控制（防止 Workers CPU 时间限制）
 * - Cache API 边缘缓存（减少上游请求）
 * - 结构化错误处理（JSON 格式响应）
 * - 安全响应头设置
 */

// ==================== 配置常量 ====================

const BING_API_URL = 'https://cn.bing.com/HPImageArchive.aspx?format=js&idx=0&n=1&mkt=zh-CN';
const BING_BASE_URL = 'https://cn.bing.com';

// 请求超时时间（毫秒）- 防止触发 Workers 30s CPU 限制
const FETCH_TIMEOUT_MS = 8000;

// 缓存配置
const CACHE_TTL_S = 600;        // 缓存有效期：10分钟
const CACHE_STALE_S = 120;      // 过期后允许使用旧数据：2分钟

// CORS 配置
const CORS_ALLOW_ORIGIN = '*';
const CORS_ALLOW_METHODS = 'GET, HEAD, OPTIONS';
const CORS_ALLOW_HEADERS = 'Content-Type';
const CORS_MAX_AGE = 86400;     // 预检请求缓存：24小时

// ==================== 错误定义 ====================

const ERROR_RESPONSES = {
  methodNotAllowed: { status: 405, message: '仅支持 GET、HEAD 和 OPTIONS 请求方法' },
  upstreamFailed: { status: 502, message: '无法获取 Bing 图片信息' },
  imageFetchFailed: { status: 502, message: '无法获取图片资源' },
  noImageData: { status: 404, message: '未找到图片信息' },
  unexpectedContentType: { status: 502, message: '上游返回了非预期的内容类型' },
  internalError: { status: 500, message: '服务器内部错误' }
};

// ==================== 工具函数 ====================

/**
 * 创建标准化错误响应
 * @param {string} errorKey - ERROR_RESPONSES 中的键名
 * @returns {Response} JSON 格式的错误响应
 */
function createErrorResponse(errorKey) {
  const { status, message } = ERROR_RESPONSES[errorKey];
  return new Response(JSON.stringify({ error: message, status }), {
    status,
    headers: {
      'Content-Type': 'application/json; charset=utf-8',
      'Cache-Control': 'no-store'
    }
  });
}

/**
 * 创建 CORS 响应头
 * @param {string} method - 请求方法
 * @returns {Object} CORS 相关的响应头对象
 */
function createCorsHeaders(method = 'GET') {
  return {
    'Access-Control-Allow-Origin': CORS_ALLOW_ORIGIN,
    'Access-Control-Allow-Methods': CORS_ALLOW_METHODS,
    'Access-Control-Allow-Headers': CORS_ALLOW_HEADERS,
    'Access-Control-Max-Age': String(CORS_MAX_AGE)
  };
}

/**
 * 创建安全响应头
 * @returns {Object} 安全相关的响应头对象
 */
function createSecurityHeaders() {
  return {
    'X-Content-Type-Options': 'nosniff',
    'X-Frame-Options': 'DENY',
    'Referrer-Policy': 'no-referrer-when-downgrade'
  };
}

/**
 * 创建图片响应头（包含缓存策略）
 * @param {string} contentType - 图片的 MIME 类型
 * @returns {Object} 完整的响应头对象
 */
function createImageCacheHeaders(contentType) {
  return {
    'Content-Type': contentType,
    'Cache-Control': `public, max-age=${CACHE_TTL_S}, s-maxage=${CACHE_TTL_S}, stale-while-revalidate=${CACHE_STALE_S}`,
    ...createCorsHeaders(),
    ...createSecurityHeaders()
  };
}

/**
 * 带超时控制的 fetch 请求
 * 使用 AbortController 实现请求超时，防止长时间阻塞
 * 
 * @param {string} url - 请求 URL
 * @param {number} timeoutMs - 超时时间（毫秒）
 * @returns {Promise<Response>} fetch 响应
 * @throws {Error} 超时或网络错误
 */
async function fetchWithTimeout(url, timeoutMs) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
  
  try {
    const response = await fetch(url, { signal: controller.signal });
    return response;
  } catch (error) {
    if (error.name === 'AbortError') {
      throw new Error(`请求超时: ${url} (${timeoutMs}ms)`);
    }
    throw error;
  } finally {
    clearTimeout(timeoutId);
  }
}

// ==================== 缓存操作 ====================

/**
 * 从 Cache API 获取缓存的图片响应
 * 利用 Cloudflare 边缘缓存减少上游请求
 * 
 * @param {Request} request - 原始请求对象
 * @param {string} cacheKeyUrl - 缓存键 URL
 * @returns {Promise<Response|null>} 缓存响应或 null
 */
async function getCachedImage(request, cacheKeyUrl) {
  const cache = caches.default;
  const cacheKey = new Request(cacheKeyUrl, { method: 'GET' });
  const cachedResponse = await cache.match(cacheKey);
  
  if (cachedResponse) {
    const headers = new Headers(cachedResponse.headers);
    headers.set('X-Cache-Status', 'HIT');
    return new Response(cachedResponse.body, {
      status: cachedResponse.status,
      headers
    });
  }
  return null;
}

/**
 * 将图片响应存入 Cache API
 * 
 * @param {string} cacheKeyUrl - 缓存键 URL
 * @param {Response} response - 要缓存的响应
 */
async function putCachedImage(cacheKeyUrl, response) {
  const cache = caches.default;
  const cacheKey = new Request(cacheKeyUrl, { method: 'GET' });
  await cache.put(cacheKey, response.clone());
}

// ==================== 业务逻辑 ====================

/**
 * 获取 Bing 图片元数据
 * 
 * @param {Object} env - 环境变量（可选配置 BING_API_URL）
 * @returns {Promise<Object>} 图片信息对象
 * @throws {Object} 包含 errorKey 的错误对象
 */
async function fetchBingImageData(env) {
  const apiUrl = env?.BING_API_URL || BING_API_URL;
  const apiResponse = await fetchWithTimeout(apiUrl, FETCH_TIMEOUT_MS);

  if (!apiResponse.ok) {
    throw { errorKey: 'upstreamFailed', statusCode: apiResponse.status };
  }

  // 验证响应内容类型
  const contentType = apiResponse.headers.get('Content-Type') || '';
  if (!contentType.includes('application/json')) {
    throw { errorKey: 'unexpectedContentType' };
  }

  const apiData = await apiResponse.json();
  const imageInfo = apiData.images?.[0];

  // 安全访问嵌套属性
  if (!imageInfo?.url) {
    throw { errorKey: 'noImageData' };
  }

  return imageInfo;
}

/**
 * 获取 Bing 图片资源
 * 
 * @param {string} imageUrl - 图片完整 URL
 * @returns {Promise<{response: Response, contentType: string}>}
 * @throws {Object} 包含 errorKey 的错误对象
 */
async function fetchBingImage(imageUrl) {
  const imageResponse = await fetchWithTimeout(imageUrl, FETCH_TIMEOUT_MS);

  if (!imageResponse.ok) {
    throw { errorKey: 'imageFetchFailed', statusCode: imageResponse.status };
  }

  // 验证响应内容类型为图片
  const contentType = imageResponse.headers.get('Content-Type') || '';
  if (!contentType.startsWith('image/')) {
    throw { errorKey: 'unexpectedContentType' };
  }

  return { response: imageResponse, contentType };
}

// ==================== 入口函数 ====================

/**
 * Cloudflare Workers 请求处理入口（ES Module 格式）
 * 支持 GET、HEAD、OPTIONS 方法
 * 
 * @param {Request} request - 请求对象
 * @param {Object} env - 环境变量绑定
 * @param {ExecutionContext} ctx - 执行上下文
 * @returns {Promise<Response>} 响应对象
 */
async function handleFetch(request, env, ctx) {
  const method = request.method.toUpperCase();

  // 处理 CORS 预检请求
  if (method === 'OPTIONS') {
    return new Response(null, {
      status: 204,
      headers: createCorsHeaders('OPTIONS')
    });
  }

  // 验证请求方法
  if (method !== 'GET' && method !== 'HEAD') {
    return createErrorResponse('methodNotAllowed');
  }

  const cacheKeyUrl = request.url;

  try {
    // 优先检查边缘缓存
    const cached = await getCachedImage(request, cacheKeyUrl);
    if (cached) return cached;

    // 获取图片元数据
    const imageInfo = await fetchBingImageData(env);
    
    // 构建图片完整 URL
    const baseUrl = env?.BING_BASE_URL || BING_BASE_URL;
    const imageUrl = baseUrl + imageInfo.url;
    
    // 获取图片资源
    const { response: imageResponse, contentType } = await fetchBingImage(imageUrl);

    // 构建最终响应
    const headers = new Headers(createImageCacheHeaders(contentType));
    headers.set('X-Cache-Status', 'MISS');

    const finalResponse = new Response(method === 'HEAD' ? null : imageResponse.body, {
      status: 200,
      headers
    });

    // 存入边缘缓存
    await putCachedImage(cacheKeyUrl, finalResponse);

    return finalResponse;

  } catch (error) {
    // 处理已知业务错误
    if (error?.errorKey) {
      return createErrorResponse(error.errorKey);
    }
    
    // 记录未知错误并返回通用错误响应
    console.error('处理请求时发生错误:', error instanceof Error ? error.message : String(error));
    return createErrorResponse('internalError');
  }
}

export default { fetch: handleFetch };

export { handleFetch as onRequest };
